### Step 2: Add or update code snippets

Write a new test sample file at:
`sdk/devopsinfrastructure/Azure.ResourceManager.DevOpsInfrastructure/tests/Samples/Sample_HelloWorld.cs`

Use the operations already demonstrated in `Sample_DevOpsPoolCollection.cs` and `Sample_DevOpsPoolResource.cs` as the basis. The snippet names must match the README placeholders above.

```
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Core;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.DevOpsInfrastructure;
using Azure.ResourceManager.DevOpsInfrastructure.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.DevOpsInfrastructure.Samples
{
    public partial class Sample_HelloWorld
    {
        [Test]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task CreateDevOpsPool()
        {
            #region Snippet:CreateDevOpsPool
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;00000000-0000-0000-0000-000000000000&#34;;
            string resourceGroupName = &#34;myResourceGroup&#34;;
            ResourceIdentifier resourceGroupResourceId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroupResource = client.GetResourceGroupResource(resourceGroupResourceId);

            DevOpsPoolCollection collection = resourceGroupResource.GetDevOpsPools();

            string poolName = &#34;myPool&#34;;
            DevOpsPoolData data = new DevOpsPoolData(new AzureLocation(&#34;eastus&#34;))
            {
                Properties = new DevOpsPoolProperties(
                    maximumConcurrency: 4,
                    organizationProfile: new DevOpsAzureOrganizationProfile(new[]
                    {
                        new DevOpsOrganization(new Uri(&#34;(dev.azure.com/redacted) { OpenAccess = true }
                    }),
                    agentProfile: new DevOpsStatelessAgentProfile(),
                    fabricProfile: new DevOpsVmssFabricProfile(&#34;Standard_D2ads_v5&#34;, new[]
                    {
                        new DevOpsPoolVmImage { ResourceId = &#34;/MicrosoftWindowsServer/WindowsServer/2022-datacenter/latest&#34; }
                    }),
                    devCenterProjectResourceId: &#34;/subscriptions/00000000-0000-0000-0000-000000000000/resourceGroups/myRg/providers/Microsoft.DevCenter/projects/myProject&#34;)
            };

            ArmOperation lro = await collection.CreateOrUpdateAsync(WaitUntil.Completed, poolName, data);
            DevOpsPoolResource pool = lro.Value;
            Console.WriteLine($&#34;Pool created: {pool.Data.Name}&#34;);
            #endregion
        }

        [Test]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task ListDevOpsPools()
        {
            #region Snippet:ListDevOpsPools
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;00000000-0000-0000-0000-000000000000&#34;;
            string resourceGroupName = &#34;myResourceGroup&#34;;
            ResourceIdentifier resourceGroupResourceId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroupResource = client.GetResourceGroupResource(resourceGroupResourceId);

            DevOpsPoolCollection collection = resourceGroupResource.GetDevOpsPools();

            await foreach (DevOpsPoolResource pool in collection.GetAllAsync())
            {
                Console.WriteLine($&#34;Pool: {pool.Data.Name}, Location: {pool.Data.Location}&#34;);
            }
            #endregion
        }

        [Test]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task GetDevOpsPool()
        {
            #region Snippet:GetDevOpsPool
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;00000000-0000-0000-0000-000000000000&#34;;
            string resourceGroupName = &#34;myResourceGroup&#34;;
            ResourceIdentifier resourceGroupResourceId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroupResource = client.GetResourceGroupResource(resourceGroupResourceId);

            DevOpsPoolResource pool = await resourceGroupResource.GetDevOpsPoolAsync(&#34;myPool&#34;);
            Console.WriteLine($&#34;Pool name: {pool.Data.Name}&#34;);
            #endregion
        }

        [Test]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task DeleteDevOpsPool()
        {
            #region Snippet:DeleteDevOpsPool
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;00000000-0000-0000-0000-000000000000&#34;;
            string resourceGroupName = &#34;myResourceGroup&#34;;
            ResourceIdentifier resourceGroupId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroupResource = client.GetResourceGroupResource(resourceGroupId);

            DevOpsPoolResource pool = await resourceGroupResource.GetDevOpsPoolAsync(&#34;myPool&#34;);
            await pool.DeleteAsync(WaitUntil.Completed);
            Console.WriteLine(&#34;Pool deleted.&#34;);
            #endregion
        }
    }
}
```

### Step 3: Verify README structure

The README at `sdk/devopsinfrastructure/Azure.ResourceManager.DevOpsInfrastructure/README.md` currently has all required sections, but the following need content updates:

1. **Key concepts** — missing; replace generic link with service-specific content (see Step 1)
2. **Examples** — missing inline code; replace generic link with snippet placeholders (see Step 1)

All other sections (Getting started, Troubleshooting, Next steps, Contributing) are present and adequate.

### Step 4: Validate

Run these commands in order. Each must succeed before proceeding to the next:

1. `dotnet build sdk/devopsinfrastructure/Azure.ResourceManager.DevOpsInfrastructure/`
2. `dotnet test sdk/devopsinfrastructure/Azure.ResourceManager.DevOpsInfrastructure/ --filter TestCategory!=Live`
3. `eng/scripts/Update-Snippets.ps1 devopsinfrastructure` — injects `#region Snippet:` code from the new test file into README.md placeholders. Check `git diff` afterwards to confirm README was updated.
4. `eng/scripts/Export-API.ps1 devopsinfrastructure` — regenerates API listing files (no public API change expected, but run to confirm)
5. `dotnet format sdk/devopsinfrastructure/Azure.ResourceManager.DevOpsInfrastructure/`



